    FOR i := 1 TO n-1 DO
        IF seq_local[i] > seq_local[i+1] THEN
            sort_successful := FALSE;
            EXIT;
        END_IF;
    END_FOR;

    (* Update outputs based on verification *)
    IF sort_successful THEN
        (* Copy sorted array back to output *)
        seq := seq_local;
        error := FALSE;
