    (* Emergency Stop Active: De-energize all outputs and reset automatic process *)
    valveARun := FALSE;
    valveBRun := FALSE;
    valveCRun := FALSE;
    valveDRun := FALSE;
    mixMotorRun := FALSE;
    autoProcessActive := FALSE;
    autoStep := 0;
ELSE
