        truck.col := 0;
        truck.VehicleNumber := 0;
        EntryFound := FALSE;
        ExitFound := FALSE;

        (* Determine next state based on request priority *)
        IF enter_flag THEN
            CurrentState := 1; (* Proceed to entry allocation *)
        ELSIF exit_flag THEN
