                (* Follow "former row first, former column first" for search order *)
                j := j + 1;
                IF j > 5 THEN
                    i := i + 1;
                    j := 1;
                    IF i > 3 THEN
                        (* Vehicle not found in garage *)
                        CurrentState := 0;
                    END_IF;
                END_IF;
                (* Remain in EXIT_SEARCH state to continue search *)
            END_IF;
        ELSE
            (* Search indices out of bounds - error recovery *)
            CurrentState := 0;
        END_IF;

