    BYTE_ARRAY_SIZE : DINT := 20; (* Size of the input byte array *)
    DWORD_ARRAY_SIZE : DINT := 10; (* Size of the output DINT array *)
END_VAR

(* Initialize output array and counter *)
FOR i := 1 TO DWORD_ARRAY_SIZE DO
    dwordArray[i] := 0;
END_FOR;
mergeDwordNum := 0;

(* Calculate maximum number of complete 4-byte chunks available *)
maxDwordCount := BYTE_ARRAY_SIZE / 4; (* Integer division truncates remainder *)

(* Limit processing by output array capacity *)
IF maxDwordCount > DWORD_ARRAY_SIZE THEN
    maxDwordCount := DWORD_ARRAY_SIZE;
END_IF;

(* Process each complete 4-byte chunk *)
dwordIdx := 1;
byteIdx := 1;
WHILE (dwordIdx <= maxDwordCount) DO
    tempDword := 0;

    (* Merge 4 bytes into one double word *)
    FOR j := 0 TO 3 DO
        currentByteValue := byteArray[byteIdx + j];

        (* Ensure byte value is in valid range (0-255) *)
        IF currentByteValue < 0 THEN
            currentByteValue := currentByteValue AND 16#000000FF;
        ELSIF currentByteValue > 255 THEN
            currentByteValue := currentByteValue AND 16#000000FF;
        END_IF;

        (* Shift byte into position and combine *)
        tempDword := tempDword OR SHL(currentByteValue, (j * 8));
    END_FOR;

    (* Store the merged double word *)
    dwordArray[dwordIdx] := tempDword;

    (* Update counters *)
    mergeDwordNum := mergeDwordNum + 1;
    dwordIdx := dwordIdx + 1;
    byteIdx := byteIdx + 4;
END_WHILE;

END_FUNCTION_BLOCK;

TYPE
    ST_LinearSegment : STRUCT
        InputMin : REAL;
        InputMax : REAL;
        OutputMin : REAL;
        OutputMax : REAL;
    END_STRUCT;

    E_StatusCode : (
        STATUS_OK := 16#0000,
        STATUS_OUT_OF_RANGE := 16#8001
    );
END_TYPE

VAR_GLOBAL CONSTANT
    gc_Segments : ARRAY[1..3] OF ST_LinearSegment := [
        (InputMin := 1200.0, InputMax := 3600.0, OutputMin := 150.0, OutputMax := 240.0),
        (InputMin := 3600.0, InputMax := 4800.0, OutputMin := 240.0, OutputMax := 560.0),
        (InputMin := 4800.0, InputMax := 7000.0, OutputMin := 560.0, OutputMax := 720.0)
    ];
    gc_InputMinLimit : REAL := 1200.0;
    gc_InputMaxLimit : REAL := 7000.0;
    gc_OutputMinLimit : REAL := 150.0;
    gc_OutputMaxLimit : REAL := 720.0;
END_VAR

FUNCTION_BLOCK FB_LinearizeValue
VAR_INPUT
    InputValue : REAL;
END_VAR

VAR_OUTPUT
    LinearizedValue : REAL;
    Error : BOOL;
    Status : WORD;
END_VAR

VAR
    iSegmentIndex : INT;
    bValueProcessed : BOOL;
END_VAR

(* Initialize outputs *)
LinearizedValue := 0.0;
Error := FALSE;
Status := E_StatusCode.STATUS_OK;
bValueProcessed := FALSE;

(* Check for out-of-range conditions *)
IF InputValue < gc_InputMinLimit THEN
    LinearizedValue := gc_OutputMinLimit;
    Error := TRUE;
    Status := E_StatusCode.STATUS_OUT_OF_RANGE;
    bValueProcessed := TRUE;
ELSIF InputValue > gc_InputMaxLimit THEN
    LinearizedValue := gc_OutputMaxLimit;
    Error := TRUE;
    Status := E_StatusCode.STATUS_OUT_OF_RANGE;
    bValueProcessed := TRUE;
END_IF;

(* Process valid ranges if not already handled *)
IF NOT bValueProcessed THEN
    FOR iSegmentIndex := 1 TO 3 DO
        IF (InputValue >= gc_Segments[iSegmentIndex].InputMin) 
           AND (InputValue <= gc_Segments[iSegmentIndex].InputMax) THEN
            LinearizedValue := gc_Segments[iSegmentIndex].OutputMin 
                + (InputValue - gc_Segments[iSegmentIndex].InputMin) 
                * (gc_Segments[iSegmentIndex].OutputMax - gc_Segments[iSegmentIndex].OutputMin)
                / (gc_Segments[iSegmentIndex].InputMax - gc_Segments[iSegmentIndex].InputMin);
            Error := FALSE;
            Status := E_StatusCode.STATUS_OK;
            bValueProcessed := TRUE;
            EXIT;
        END_IF;
    END_FOR;
END_IF;

(* Handle edge case: value within global limits but not in any segment *)
IF NOT bValueProcessed THEN
    LinearizedValue := 0.0;
    Error := TRUE;
    Status := E_StatusCode.STATUS_OUT_OF_RANGE;
END_IF;

END_FUNCTION_BLOCK;

TYPE
    ST_WarehouseStatus :
        STRUCT
            productNum : INT;
            libFreeNum : INT;
            error : BOOL;
            status : WORD;
        END_STRUCT;
    ARRAY_StoragePositions : ARRAY[1..9] OF BOOL;
END_TYPE

FUNCTION_BLOCK FB_WarehouseManagement
VAR_INPUT
    requestIn : BOOL := FALSE;
    requestOut : BOOL := FALSE;
END_VAR

VAR_OUTPUT
    productNum : INT := 0;
    libFreeNum : INT := 9;
    error : BOOL := FALSE;
    status : WORD := 16#0000;
END_VAR

VAR_IN_OUT
    library : ARRAY_StoragePositions;
END_VAR

VAR
    i : INT;
    found : BOOL;
    errFull : WORD := 16#8001;
    errEmpty : WORD := 16#8002;
    initDone : BOOL := FALSE;
END_VAR

(* Reset error status at start of each cycle *)
error := FALSE;
status := 16#0000;

(* Initialize library array on first execution *)
IF NOT initDone THEN
    i := 1;
    WHILE i <= 9 DO
        library[i] := FALSE;
        i := i + 1;
    END_WHILE;
    initDone := TRUE;
END_IF;

(* Calculate current product count and free positions *)
productNum := 0;
i := 1;
WHILE i <= 9 DO
    IF library[i] THEN
        productNum := productNum + 1;
    END_IF;
    i := i + 1;
END_WHILE;
libFreeNum := 9 - productNum;

(* Handle product storage request *)
IF requestIn THEN
    (* Check for storage full condition *)
    IF productNum >= 9 THEN
        error := TRUE;
        status := errFull;
    ELSE
        (* Search for free position from highest to lowest index (FILO) *)
        found := FALSE;
        i := 9;
        WHILE i >= 1 AND NOT found DO
            IF NOT library[i] THEN
                library[i] := TRUE;
                found := TRUE;
            END_IF;
            i := i - 1;
        END_WHILE;

        (* Update counters if position was found *)
        IF found THEN
            productNum := productNum + 1;
            libFreeNum := libFreeNum - 1;
        END_IF;
    END_IF;
END_IF;

(* Handle product retrieval request *)
IF requestOut THEN
    (* Check for storage empty condition *)
    IF productNum <= 0 THEN
        error := TRUE;
        status := errEmpty;
    ELSE
        (* Search for occupied position from lowest to highest index (FIFO) *)
        found := FALSE;
        i := 1;
        WHILE i <= 9 AND NOT found DO
            IF library[i] THEN
                library[i] := FALSE;
                found := TRUE;
            END_IF;
            i := i + 1;
        END_WHILE;

        (* Update counters if position was found *)
        IF found THEN
            productNum := productNum - 1;
            libFreeNum := libFreeNum + 1;
        END_IF;
    END_IF;
END_IF;

(* Validate counter consistency - safety check *)
IF (productNum + libFreeNum) <> 9 THEN
    error := TRUE;
    status := 16#8003;  (* Internal consistency error *)
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_ColorLightControl
{ S7_Optimized_Access := 'TRUE' }
VAR_INPUT
    controlButton : BOOL; // Push button for sequence control
END_VAR

VAR_OUTPUT
    greenLight : BOOL; // Green light control signal
    redLight : BOOL; // Red light control signal
    yellowLight : BOOL; // Yellow light control signal
END_VAR

VAR
    state : INT := 1; // State machine control variable
    lastControlButton : BOOL := FALSE; // Previous button state
END_VAR

// Main logic
IF controlButton AND NOT lastControlButton THEN
    // Rising edge detected - execute state transition
    CASE state OF
        1: // State 1: Green Only
            greenLight := TRUE;
            redLight := FALSE;
            yellowLight := FALSE;
            state := 2;

        2: // State 2: Red Only
            greenLight := FALSE;
            redLight := TRUE;
            yellowLight := FALSE;
            state := 3;

        3: // State 3: Yellow Only
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := TRUE;
            state := 4;

        4: // State 4: All Lights On
            greenLight := TRUE;
            redLight := TRUE;
            yellowLight := TRUE;
            state := 5;

        5: // State 5: All Lights Off
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := FALSE;
            state := 1;

        ELSE // Handle unexpected state (safety fallback)
            state := 1;
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := FALSE;
    END_CASE;
ELSE
    // No rising edge - maintain current state outputs
    CASE state OF
        1: // State 1: Green Only
            greenLight := TRUE;
            redLight := FALSE;
            yellowLight := FALSE;

        2: // State 2: Red Only
            greenLight := FALSE;
            redLight := TRUE;
            yellowLight := FALSE;

        3: // State 3: Yellow Only
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := TRUE;

        4: // State 4: All Lights On
            greenLight := TRUE;
            redLight := TRUE;
            yellowLight := TRUE;

        5: // State 5: All Lights Off
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := FALSE;

        ELSE // Safety fallback for unexpected state
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := FALSE;
    END_CASE;
END_IF;

// Update last button state for edge detection in next cycle
lastControlButton := controlButton;

END_FUNCTION_BLOCK;

FUNCTION_BLOCK FB_DatabaseManager
VAR_INPUT
    dataInput : ARRAY[0..5] OF BYTE;
    storeTrigger : BOOL;
    resetTrigger : BOOL;
END_VAR

VAR_OUTPUT
    usedSpace : INT := 0;
    remainingSpace : INT := 20;
    error : BOOL;
    status : WORD;
END_VAR

VAR_IN_OUT
    dataBase : ARRAY[1..20] OF BYTE;
END_VAR

VAR
    dataLength : INT;
    i : INT;
END_VAR

(* Reset Operation - Highest Priority *)
IF resetTrigger THEN
    (* Clear database array *)
    FOR i := 1 TO 20 DO
        dataBase[i] := 0;
    END_FOR;

    (* Reset counters *)
    usedSpace := 0;
    remainingSpace := 20;

    (* Clear status *)
    error := FALSE;
    status := 0;

(* Store Operation - Conditional Execution *)
ELSIF storeTrigger THEN
    (* Extract and validate data length *)
    dataLength := dataInput[0];

    (* Length Validation *)
    IF (dataLength <= 0) OR (dataLength > 5) THEN
        error := TRUE;
        status := 16#8001;  (* Invalid data length *)

    (* Space Verification *)
    ELSIF (usedSpace + dataLength) > 20 THEN
        error := TRUE;
        status := 16#8002;  (* Insufficient space *)

    (* Data Storage *)
    ELSE
        (* Copy data bytes to database *)
        FOR i := 1 TO dataLength DO
            dataBase[usedSpace + i] := dataInput[i];
        END_FOR;

        (* Update space tracking *)
        usedSpace := usedSpace + dataLength;
        remainingSpace := 20 - usedSpace;

        (* Set success status *)
        error := FALSE;
        status := 0;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_ProductionLineControl
VAR_INPUT
    Mode : BOOL;            // Manual/Auto mode selection
    ForwardButton : BOOL;   // Forward rotation button
    ReverseButton : BOOL;   // Reverse rotation button
    SensorA : BOOL;         // Sensor A input
    SensorB : BOOL;         // Sensor B input
    SensorC : BOOL;         // Sensor C input
    ButtonA : BOOL;         // Button A input
    ButtonB : BOOL;         // Button B input
    ButtonC : BOOL;         // Button C input
