    MotorReverse : BOOL;    // Motor reverse output
    CompletionLight : BOOL; // Process completion indicator
END_VAR

VAR
    State : INT := 0;       // State machine current state
END_VAR

// Main execution logic
CASE State OF
    0: // Initialization state
        MotorForward := FALSE;
        MotorReverse := FALSE;
        CompletionLight := FALSE;
        State := 1;

    1: // State 1: Waiting at Station A
        IF NOT Mode THEN // Manual Mode
            // Manual motor control with mutual exclusion
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic Mode
            // Safety: Ensure reverse motor is off in auto mode
            MotorReverse := FALSE;
            MotorForward := FALSE;

            // Wait for SensorA activation
            IF SensorA THEN
                State := 2;
            END_IF;
        END_IF;

    2: // State 2: Processing at Station A
        IF NOT Mode THEN // Manual Mode
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic Mode
            MotorReverse := FALSE;
            MotorForward := FALSE;

            // Wait for ButtonA press
            IF ButtonA THEN
                MotorForward := TRUE;
                State := 3;
            END_IF;
        END_IF;

    3: // State 3: Moving to Station B
        IF NOT Mode THEN // Manual Mode
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic Mode
            MotorReverse := FALSE;

            // Wait for SensorB activation
            IF SensorB THEN
                MotorForward := FALSE;
                State := 4;
            END_IF;
        END_IF;

    4: // State 4: Processing at Station B
        IF NOT Mode THEN // Manual Mode
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic Mode
            MotorReverse := FALSE;
            MotorForward := FALSE;

            // Wait for ButtonB press
            IF ButtonB THEN
                MotorForward := TRUE;
                State := 5;
            END_IF;
        END_IF;

    5: // State 5: Moving to Station C
        IF NOT Mode THEN // Manual Mode
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic Mode
            MotorReverse := FALSE;

            // Wait for SensorC activation
            IF SensorC THEN
                MotorForward := FALSE;
                State := 6;
            END_IF;
        END_IF;

    6: // State 6: Processing at Station C
        IF NOT Mode THEN // Manual Mode
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic Mode
            MotorReverse := FALSE;
            MotorForward := FALSE;

            // Wait for ButtonC press
            IF ButtonC THEN
                CompletionLight := TRUE;
                State := 7;
            END_IF;
        END_IF;

    7: // State 7: Cycle Completion
        IF NOT Mode THEN // Manual Mode
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic Mode
            MotorReverse := FALSE;
            MotorForward := FALSE;

            // Wait for product removal (SensorC deactivation)
            IF NOT SensorC THEN
                CompletionLight := FALSE;
                State := 1;
            END_IF;
        END_IF;

END_CASE;

END_FUNCTION_BLOCK;

FUNCTION_BLOCK FB_SplitNumber
VAR_INPUT
    InputNumber : INT;
END_VAR

VAR_OUTPUT
    Thousands : INT;
    Hundreds : INT;
    Tens : INT;
    Ones : INT;
    Min : INT;
    error : BOOL;
    status : WORD;
END_VAR

VAR
    tempNumber : INT;
    minValue : INT;
    digitProcessed : BOOL;
END_VAR

(* Input Validation *)
IF (InputNumber < 0) OR (InputNumber > 9999) THEN
    (* Error case: Input out of valid range *)
    error := TRUE;
    status := 16#8001;

    (* Zero all outputs *)
    Thousands := 0;
    Hundreds := 0;
    Tens := 0;
    Ones := 0;
    Min := 0;
ELSE
    (* Valid case: Normal operation *)
    error := FALSE;
    status := 16#0000;

    (* Digit Separation Logic *)
    tempNumber := InputNumber;
    Thousands := tempNumber / 1000;
    tempNumber := tempNumber MOD 1000;
    Hundreds := tempNumber / 100;
    tempNumber := tempNumber MOD 100;
    Tens := tempNumber / 10;
    Ones := tempNumber MOD 10;

    (* Minimum Non-Zero Digit Detection *)
    minValue := 0;
    digitProcessed := FALSE;

    (* Process each digit sequentially, excluding zeros *)
    IF Thousands <> 0 THEN
        minValue := Thousands;
        digitProcessed := TRUE;
    END_IF;

    IF Hundreds <> 0 THEN
        IF digitProcessed THEN
            minValue := minimal(minValue, Hundreds);
        ELSE
            minValue := Hundreds;
            digitProcessed := TRUE;
        END_IF;
    END_IF;

    IF Tens <> 0 THEN
        IF digitProcessed THEN
            minValue := minimal(minValue, Tens);
        ELSE
            minValue := Tens;
            digitProcessed := TRUE;
        END_IF;
    END_IF;

    IF Ones <> 0 THEN
        IF digitProcessed THEN
            minValue := minimal(minValue, Ones);
        ELSE
            minValue := Ones;
            digitProcessed := TRUE;
        END_IF;
    END_IF;

    (* Set final Min output *)
    IF NOT digitProcessed THEN
        (* All digits were zero *)
        Min := 0;
    ELSE
        Min := minValue;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

(* Provided minimal function *)
FUNCTION minimal : INT
VAR_INPUT
    IN1 : INT;
    IN2 : INT;
END_VAR

IF IN1 <= IN2 THEN
    minimal := IN1;
ELSE
    minimal := IN2;
END_IF;

END_FUNCTION

