        - If done = TRUE: Transition to State 0, set listen = TRUE
*)

FUNCTION_BLOCK FB_RequestHandler
VAR_INPUT
    request : BOOL;
    done    : BOOL;
END_VAR

VAR_OUTPUT
    listen : BOOL;
END_VAR

VAR
    state : INT := 0;
END_VAR

(* Main state machine logic *)
CASE state OF
    0: (* State 0: Idle/Listening *)
        listen := TRUE;

        IF request THEN
            listen := FALSE;
            state := 1;
        END_IF;

    1: (* State 1: Processing/Not Listening *)
        listen := FALSE;

        IF done THEN
            listen := TRUE;
            state := 0;
        END_IF;

END_CASE;

END_FUNCTION_BLOCK;

TYPE
    E_Status : (eIdle, eRunning, eDone, eError);
END_TYPE

TYPE
    ST_SumData :
    STRUCT
        maxValue : INT;
        wData : DWORD; (* Changed from WORD to DWORD to prevent overflow *)
        currentIndex : INT;
        status : E_Status;
    END_STRUCT
END_TYPE

FUNCTION_BLOCK FB_Sum
VAR_INPUT
    maxValue : INT;
    bExecute : BOOL; (* Added for stateful execution control *)
END_VAR
VAR_OUTPUT
    wData : DWORD; (* Changed from WORD to DWORD *)
    status : E_Status;
    bDone : BOOL;
    bError : BOOL;
END_VAR
VAR
    internalData : ST_SumData;
    bExecutePrev : BOOL;
END_VAR

(* Initialize on first execution or when not executing *)
IF NOT bExecute AND bExecutePrev THEN
    internalData.status := eIdle;
    internalData.wData := 0;
    internalData.currentIndex := 0;
    bDone := FALSE;
    bError := FALSE;
END_IF;

(* Main execution logic *)
CASE internalData.status OF
    eIdle:
        IF bExecute AND NOT bExecutePrev THEN
            (* Validate input *)
            IF maxValue < 0 THEN
                internalData.status := eError;
                bError := TRUE;
            ELSE
                internalData.maxValue := maxValue;
                internalData.wData := 0;
                internalData.currentIndex := 0;
                internalData.status := eRunning;
            END_IF;
        END_IF;

    eRunning:
        IF internalData.currentIndex <= internalData.maxValue THEN
            internalData.wData := internalData.wData + DWORD_TO_DWORD(internalData.currentIndex);
            internalData.currentIndex := internalData.currentIndex + 1;
        ELSE
            internalData.status := eDone;
            bDone := TRUE;
        END_IF;

    eDone:
        (* Maintain state until execution command is released *)
        IF NOT bExecute THEN
            internalData.status := eIdle;
            bDone := FALSE;
        END_IF;

    eError:
        (* Maintain error state until execution command is released *)
        IF NOT bExecute THEN
            internalData.status := eIdle;
            bError := FALSE;
        END_IF;
END_CASE;

(* Update outputs *)
wData := internalData.wData;
status := internalData.status;

(* Store previous execute state for edge detection *)
bExecutePrev := bExecute;

END_FUNCTION_BLOCK;

(*
FUNCTION_BLOCK: FB_PedestrianTrafficLight
DESCRIPTION: Pedestrian traffic light control system with state machine logic.
INPUTS:
  - pedBtnPress: Pedestrian button press signal (rising edge detection)
OUTPUTS:
  - carLightIsGreen: Car traffic light green status
  - pedLightIsGreen: Pedestrian light green status
  - TimeCounter: Current timer value for state transitions
STATES:
  1: IDLE - Car green, pedestrian red, waiting for button press
  2: CAR_RED - Car red, pedestrian red, counting to pedestrian green
  3: PED_GREEN - Car red, pedestrian green, counting to pedestrian red
  4: PED_RED - Car red, pedestrian red, counting to car green
*)

FUNCTION_BLOCK FB_PedestrianTrafficLight
VAR_INPUT
    pedBtnPress : BOOL; (* Pedestrian button input *)
END_VAR

VAR_OUTPUT
    carLightIsGreen : BOOL; (* Car light status *)
    pedLightIsGreen : BOOL; (* Pedestrian light status *)
    TimeCounter : INT; (* Current counter value *)
END_VAR

VAR
    buttonPressedBefore : BOOL := FALSE; (* Rising edge detection *)
    currentState : INT := 1; (* Current state (1-4) *)
    nextState : INT := 1; (* Next state for transition *)
    pedBtnPressRisingEdge : BOOL; (* Rising edge detection internal *)
END_VAR

(* Rising edge detection for pedestrian button *)
pedBtnPressRisingEdge := pedBtnPress AND NOT buttonPressedBefore;
buttonPressedBefore := pedBtnPress;

(* Main state machine logic *)
CASE currentState OF
    1: (* IDLE: Car green, pedestrian red *)
        carLightIsGreen := TRUE;
        pedLightIsGreen := FALSE;
        TimeCounter := 0;

        IF pedBtnPressRisingEdge THEN
            nextState := 2;
        ELSE
            nextState := 1;
        END_IF;

    2: (* CAR_RED: Car red, pedestrian red, counting to 10 *)
        carLightIsGreen := FALSE;
        pedLightIsGreen := FALSE;
        TimeCounter := TimeCounter + 1;

        IF TimeCounter >= 10 THEN
            nextState := 3;
        ELSE
            nextState := 2;
        END_IF;

    3: (* PED_GREEN: Car red, pedestrian green, counting to 40 *)
        carLightIsGreen := FALSE;
        pedLightIsGreen := TRUE;
        TimeCounter := TimeCounter + 1;

        IF TimeCounter >= 40 THEN
            nextState := 4;
        ELSE
            nextState := 3;
        END_IF;

    4: (* PED_RED: Car red, pedestrian red, counting to 50 *)
        carLightIsGreen := FALSE;
        pedLightIsGreen := FALSE;
        TimeCounter := TimeCounter + 1;

        IF TimeCounter >= 50 THEN
            nextState := 1;
        ELSE
            nextState := 4;
        END_IF;

END_CASE;

(* State transition *)
currentState := nextState;

END_FUNCTION_BLOCK;

