(* ============================================================================
   Bakery Oven Control System
   FUNCTION_BLOCK: BakeryOvenControl
   Description: Implements temperature and humidity regulation with deadband
                control and a baking timer. Ensures safe, mutually exclusive
                operation of opposing control elements.
   Author: Senior PLC Commissioning Engineer
   IEC 61131-3 Compliant
============================================================================ *)

FUNCTION_BLOCK BakeryOvenControl
VAR_INPUT
    TemperatureSensor : REAL;     (* Current oven temperature measurement (°C) *)
    HumiditySensor    : REAL;     (* Current oven humidity measurement (%RH) *)
END_VAR

VAR_OUTPUT
    HeatingElement    : BOOL;     (* Control output for heating element *)
    CoolingElement    : BOOL;     (* Control output for cooling element *)
    HumidityControl   : BOOL;     (* Control output for humidification system *)
    DehumidityControl : BOOL;     (* Control output for dehumidification system *)
    TimerRemaining    : TIME;     (* Remaining baking time for display/feedback *)
    OvenActive        : BOOL;     (* Status: TRUE when oven is on and timer > 0 *)
END_VAR

VAR
    (* Process Setpoints - Initialized when oven is off *)
    TemperatureSetpoint : REAL := 180.0;   (* Desired oven temperature (°C) *)
    HumiditySetpoint    : REAL := 60.0;    (* Desired oven humidity (%RH) *)
    BakingTimeSet       : TIME := T#30m;   (* Total baking duration *)

    (* Control Parameters *)
    TemperatureThreshold : REAL := 2.0;    (* Deadband for temperature control (°C) *)
    HumidityThreshold    : REAL := 5.0;    (* Deadband for humidity control (%RH) *)

    (* Internal State Variables *)
    OvenStatus      : BOOL := FALSE;       (* Master enable: TRUE=On, FALSE=Off *)
    TimerActive     : BOOL := FALSE;       (* Timer is currently counting down *)
    TimerOneSec     : TON;                 (* One-second interval timer *)

    (* Calculated Bounds for Control *)
    TempLowerBound  : REAL;
    TempUpperBound  : REAL;
    HumidLowerBound : REAL;
    HumidUpperBound : REAL;

    (* Internal Timer Variable *)
    internalTimerRemaining : TIME := T#0s;
END_VAR

(* ============================================================================
   Initialization and Timer Management
   - Setpoints can be configured when oven is off
   - Timer decrements at 1-second intervals when active
============================================================================ *)

(* Initialize setpoints and reset outputs when oven is turned off *)
IF NOT OvenStatus THEN
    (* Reset all control outputs *)
    HeatingElement    := FALSE;
    CoolingElement    := FALSE;
    HumidityControl   := FALSE;
    DehumidityControl := FALSE;

    (* Reset timer state *)
    TimerActive := FALSE;
    internalTimerRemaining := BakingTimeSet;
    TimerOneSec(IN:=FALSE, PT:=T#1s);

    (* Setpoints can be modified here when oven is off *)
    (* Note: In a real application, these would typically be set via HMI or recipe *)
ELSE
    (* Start timer when oven is turned on *)
    IF NOT TimerActive THEN
        TimerActive := TRUE;
        internalTimerRemaining := BakingTimeSet;
    END_IF;
END_IF;

(* One-second timer for decrementing baking time *)
TimerOneSec(IN:=TimerActive AND (internalTimerRemaining > T#0s), PT:=T#1s);

(* Decrement timer at one-second intervals *)
IF TimerOneSec.Q THEN
    IF internalTimerRemaining >= T#1s THEN
        internalTimerRemaining := internalTimerRemaining - T#1s;
    ELSE
        internalTimerRemaining := T#0s;
    END_IF;
    TimerOneSec(IN:=FALSE);  (* Reset timer for next interval *)
END_IF;

(* Stop timer and deactivate oven when time reaches zero *)
IF internalTimerRemaining = T#0s THEN
    TimerActive := FALSE;
    OvenStatus := FALSE;
END_IF;

(* Update output variable for remaining time *)
TimerRemaining := internalTimerRemaining;

(* Oven is considered active only when both enabled and timer is running *)
OvenActive := OvenStatus AND TimerActive AND (internalTimerRemaining > T#0s);

(* ============================================================================
   Safety Validation and Bound Calculation
   - Ensure thresholds are positive to prevent inverted control logic
   - Calculate control bounds with validated thresholds
============================================================================ *)

(* Validate thresholds are positive - use absolute value as safety measure *)
TemperatureThreshold := ABS(TemperatureThreshold);
HumidityThreshold := ABS(HumidityThreshold);

(* Ensure minimum threshold values to prevent excessive cycling *)
IF TemperatureThreshold < 0.1 THEN
    TemperatureThreshold := 0.1;
END_IF;

IF HumidityThreshold < 0.5 THEN
    HumidityThreshold := 0.5;
END_IF;

(* Calculate control bounds *)
TempLowerBound  := TemperatureSetpoint - TemperatureThreshold;
TempUpperBound  := TemperatureSetpoint + TemperatureThreshold;
HumidLowerBound := HumiditySetpoint - HumidityThreshold;
HumidUpperBound := HumiditySetpoint + HumidityThreshold;

(* ============================================================================
   Temperature Control Logic
   - Heating activates when temperature < lower bound
   - Cooling activates when temperature > upper bound
   - Explicit mutual exclusion between heating and cooling
   - Both off when within deadband
============================================================================ *)

IF OvenActive THEN
    (* Temperature Control with Explicit Mutual Exclusion *)
    IF TemperatureSensor < TempLowerBound THEN
        (* Temperature too low - activate heating *)
        HeatingElement := TRUE;
        CoolingElement := FALSE;
    ELSIF TemperatureSensor > TempUpperBound THEN
        (* Temperature too high - activate cooling *)
        HeatingElement := FALSE;
        CoolingElement := TRUE;
    ELSE
        (* Temperature within acceptable range *)
        HeatingElement := FALSE;
        CoolingElement := FALSE;
    END_IF;

    (* Humidity Control with Explicit Mutual Exclusion *)
    IF HumiditySensor < HumidLowerBound THEN
        (* Humidity too low - activate humidification *)
        HumidityControl := TRUE;
        DehumidityControl := FALSE;
    ELSIF HumiditySensor > HumidUpperBound THEN
        (* Humidity too high - activate dehumidification *)
        HumidityControl := FALSE;
        DehumidityControl := TRUE;
    ELSE
        (* Humidity within acceptable range *)
        HumidityControl := FALSE;
        DehumidityControl := FALSE;
    END_IF;
ELSE
    (* Oven not active - force all outputs off *)
    HeatingElement    := FALSE;
    CoolingElement    := FALSE;
    HumidityControl   := FALSE;
    DehumidityControl := FALSE;
END_IF;

(* ============================================================================
   Final Safety Interlock
   - Redundant protection against simultaneous activation
   - Ensures outputs are forced off when oven is not active
============================================================================ *)

(* Final mutual exclusion check - redundant safety *)
IF HeatingElement AND CoolingElement THEN
    HeatingElement := FALSE;
    CoolingElement := FALSE;
END_IF;

IF HumidityControl AND DehumidityControl THEN
    HumidityControl := FALSE;
    DehumidityControl := FALSE;
END_IF;

(* Master disable - final override *)
IF NOT OvenActive THEN
    HeatingElement    := FALSE;
    CoolingElement    := FALSE;
    HumidityControl   := FALSE;
    DehumidityControl := FALSE;
END_IF;

END_FUNCTION_BLOCK;

FUNCTION_BLOCK TheaterControl
VAR_INPUT
    StartButton : BOOL; (* Input for starting a performance *)
    StopButton : BOOL; (* Input for stopping a performance *)
    SceneNumber : INT; (* Input for selecting the scene or act *)
END_VAR

VAR_OUTPUT
    LightingControl : BOOL; (* Output for controlling lighting *)
    SoundControl : BOOL; (* Output for controlling sound *)
    PerformanceInProgress : BOOL; (* Indicator for an ongoing performance *)
END_VAR

VAR
    bStartRisingEdge : BOOL; (* Detects rising edge of StartButton *)
    bPrevStartState : BOOL; (* Previous state for edge detection *)
END_VAR

(* Rising edge detection for StartButton *)
bStartRisingEdge := StartButton AND NOT bPrevStartState;
bPrevStartState := StartButton;

(* Main control logic with StopButton as highest priority *)
IF StopButton THEN
    (* Immediate halt: override all other inputs *)
    PerformanceInProgress := FALSE;
    LightingControl := FALSE;
    SoundControl := FALSE;
ELSIF bStartRisingEdge AND NOT PerformanceInProgress THEN
    (* Start attempt when not already in progress *)
    IF (SceneNumber >= 1) AND (SceneNumber <= 3) THEN
        (* Valid scene: activate performance *)
        PerformanceInProgress := TRUE;
        LightingControl := TRUE;
        SoundControl := TRUE;
    ELSE
        (* Invalid scene: ensure all outputs are FALSE *)
        PerformanceInProgress := FALSE;
        LightingControl := FALSE;
        SoundControl := FALSE;
    END_IF;
END_IF;

(* Note: Once started, outputs remain TRUE until StopButton is pressed.
   The PerformanceInProgress state persists between cycles, 
   preventing re-triggering while active. *)
END_FUNCTION_BLOCK;

(*
    Elevator Control System Function Block
    Author: Senior PLC Commissioning Engineer
    Description: Controls elevator movement and door operations based on position requests
    Compliance: IEC 61131-3 Structured Text
*)

FUNCTION_BLOCK ElevatorControl
VAR_INPUT
    CurrentPos : INT;           (* Current floor position *)
    RequestedPos : INT;         (* Target floor position *)
    ButtonPressed : BOOL;       (* Button press trigger *)
END_VAR

VAR_OUTPUT
    MotorMovingUp : BOOL;       (* Elevator moving upward *)
    MotorMovingDown : BOOL;     (* Elevator moving downward *)
    DoorIsOpen : BOOL;          (* Door open status *)
END_VAR

VAR
    (* State machine enumeration *)
    State : (IDLE, MOVING_UP, MOVING_DOWN);

    (* Edge detection for button press *)
    PrevButtonPressed : BOOL := FALSE;

    (* Internal target storage for dynamic updates *)
    ActiveTarget : INT := 0;

    (* Safety flag to prevent simultaneous motor activation *)
    MotorActive : BOOL := FALSE;
END_VAR

(* Main state machine logic *)
CASE State OF
    IDLE:
        (* Stationary state - door open, motors off *)
        MotorMovingUp := FALSE;
        MotorMovingDown := FALSE;
        DoorIsOpen := TRUE;
        MotorActive := FALSE;

        (* Check for new button press with edge detection *)
        IF ButtonPressed AND NOT PrevButtonPressed THEN
            (* Store the requested position for dynamic updates *)
            ActiveTarget := RequestedPos;

            (* Determine movement direction *)
            IF ActiveTarget > CurrentPos THEN
                State := MOVING_UP;
                DoorIsOpen := FALSE;
                MotorMovingUp := TRUE;
                MotorActive := TRUE;
            ELSIF ActiveTarget < CurrentPos THEN
                State := MOVING_DOWN;
                DoorIsOpen := FALSE;
                MotorMovingDown := TRUE;
                MotorActive := TRUE;
            ELSE
                (* Already at target floor *)
                DoorIsOpen := TRUE;
                State := IDLE;
            END_IF;
        END_IF;

        (* Monitor for dynamic target updates while idle *)
        IF RequestedPos <> ActiveTarget AND ButtonPressed AND NOT PrevButtonPressed THEN
            ActiveTarget := RequestedPos;
        END_IF;

    MOVING_UP:
        (* Elevator moving upward *)
        MotorMovingUp := TRUE;
        MotorMovingDown := FALSE;
        DoorIsOpen := FALSE;
        MotorActive := TRUE;

        (* Check for dynamic target updates during movement *)
        IF RequestedPos <> ActiveTarget THEN
            ActiveTarget := RequestedPos;

            (* Re-evaluate direction if target changes *)
            IF ActiveTarget < CurrentPos THEN
                State := MOVING_DOWN;
            ELSIF ActiveTarget = CurrentPos THEN
                State := IDLE;
            END_IF;
        END_IF;

        (* Check if target floor reached *)
        IF CurrentPos >= ActiveTarget THEN
            (* Exact position check for safety *)
            IF CurrentPos = ActiveTarget THEN
                State := IDLE;
                MotorMovingUp := FALSE;
                DoorIsOpen := TRUE;
                MotorActive := FALSE;
            END_IF;
        END_IF;

    MOVING_DOWN:
        (* Elevator moving downward *)
        MotorMovingUp := FALSE;
        MotorMovingDown := TRUE;
        DoorIsOpen := FALSE;
        MotorActive := TRUE;

        (* Check for dynamic target updates during movement *)
        IF RequestedPos <> ActiveTarget THEN
            ActiveTarget := RequestedPos;

            (* Re-evaluate direction if target changes *)
            IF ActiveTarget > CurrentPos THEN
                State := MOVING_UP;
            ELSIF ActiveTarget = CurrentPos THEN
                State := IDLE;
            END_IF;
        END_IF;

        (* Check if target floor reached *)
        IF CurrentPos <= ActiveTarget THEN
            (* Exact position check for safety *)
            IF CurrentPos = ActiveTarget THEN
                State := IDLE;
                MotorMovingDown := FALSE;
                DoorIsOpen := TRUE;
                MotorActive := FALSE;
            END_IF;
        END_IF;

END_CASE;

(* Update button press history for edge detection *)
PrevButtonPressed := ButtonPressed;

(* Safety interlock: Ensure motors are never active simultaneously *)
IF MotorMovingUp AND MotorMovingDown THEN
    MotorMovingUp := FALSE;
    MotorMovingDown := FALSE;
    MotorActive := FALSE;
    State := IDLE;
END_IF;

END_FUNCTION_BLOCK

TYPE
    E_CalculationStatus : (eStatus_InvalidInput, eStatus_ValidInput, eStatus_OverflowPrevented);
END_TYPE

FUNCTION_BLOCK FB_FactorialCalculator
VAR_INPUT
    X : INT;
END_VAR

VAR_OUTPUT
    FactorialResult : INT;
    FactorialGoodResult : INT;
    eStatus : E_CalculationStatus;
END_VAR

VAR
    nTempGoodResult : INT;
END_VAR

(* Initialize outputs *)
FactorialGoodResult := 0;
FactorialResult := 1;
eStatus := eStatus_InvalidInput;

(* Check input range *)
IF (X >= -3) AND (X <= 3) THEN
    (* Calculate FactorialGoodResult as X⁴ *)
    nTempGoodResult := X * X * X * X;
    FactorialGoodResult := nTempGoodResult;

    (* Calculate FactorialResult based on FactorialGoodResult *)
    IF nTempGoodResult > 1 THEN
        FactorialResult := nTempGoodResult * (nTempGoodResult - 1);
    ELSE
        FactorialResult := nTempGoodResult;
    END_IF;

    eStatus := eStatus_ValidInput;
ELSE
    (* Handle out-of-range input to prevent overflow *)
    FactorialGoodResult := 0;
    FactorialResult := 1;
    eStatus := eStatus_OverflowPrevented;
END_IF;

END_FUNCTION_BLOCK;

