(* Pair 1 *)
IF tmpLight1 THEN
    GreenTimer1(IN:=TRUE, PT:=MinimumGreenTime);
    IF NOT GreenTimer1.Q THEN
        tmpLight1 := FALSE;
        tmpLight2 := FALSE;
        YellowLight1 := TRUE;
    ELSE
        YellowLight1 := FALSE;
    END_IF;
ELSE
    GreenTimer1(IN:=FALSE);
    YellowLight1 := FALSE;
END_IF;

IF tmpLight2 THEN
    GreenTimer2(IN:=TRUE, PT:=MinimumGreenTime);
    IF NOT GreenTimer2.Q THEN
        tmpLight1 := FALSE;
        tmpLight2 := FALSE;
        YellowLight2 := TRUE;
    ELSE
        YellowLight2 := FALSE;
    END_IF;
ELSE
    GreenTimer2(IN:=FALSE);
    YellowLight2 := FALSE;
END_IF;

