IF tmpLight3 THEN
    GreenTimer3(IN:=TRUE, PT:=MinimumGreenTime);
    IF NOT GreenTimer3.Q THEN
        tmpLight3 := FALSE;
        tmpLight4 := FALSE;
        YellowLight3 := TRUE;
