TrafficLight1 := tmpLight1;
TrafficLight2 := tmpLight2;
TrafficLight3 := tmpLight3;
TrafficLight4 := tmpLight4;

(* Fault detection *)
FaultCondition := (VehicleCount1 < 0) OR (VehicleCount2 < 0) OR 
