FUNCTION_BLOCK SoilTestingDeviceControl
VAR_INPUT
    StartButton : BOOL; (* Input for starting the testing process *)
    SoilSampleDetected : BOOL; (* Input for detecting soil sample *)
END_VAR
VAR_OUTPUT
    NutrientPump : BOOL; (* Output to control nutrient pump *)
    pHAdjustmentPump : BOOL; (* Output to control pH adjustment pump *)
END_VAR
VAR
    pHSensorValue : REAL; (* Simulated pH sensor value *)
    NutrientSensorValue : REAL; (* Simulated nutrient sensor value *)
    TestingStatus : INT; (* Status: 0=Idle, 1=Testing, 2=Completed *)
    NutrientThreshold : REAL := 0.7; (* Nutrient level threshold for analysis *)
    pHThreshold : REAL := 6.5; (* pH level threshold for analysis *)
    tSampleVerification : TON; (* Timer for sample verification delay *)
    bStartButtonPrev : BOOL; (* Edge detection for StartButton *)
    bSampleDetectedPrev : BOOL; (* Edge detection for SoilSampleDetected *)
END_VAR

(* State Machine Implementation *)
CASE TestingStatus OF
    0: (* Idle State *)
        (* Initialize sensor values *)
        pHSensorValue := 7.0;
        NutrientSensorValue := 0.5;

        (* Ensure pumps are deactivated *)
        NutrientPump := FALSE;
        pHAdjustmentPump := FALSE;

        (* Reset verification timer *)
        tSampleVerification(IN:=FALSE, PT:=T#2S);

        (* Detect rising edge of StartButton to transition to Testing state *)
        IF StartButton AND NOT bStartButtonPrev THEN
            TestingStatus := 1;
            (* Activate pumps upon transition *)
            NutrientPump := TRUE;
            pHAdjustmentPump := TRUE;
        END_IF;

        (* Store current button state for next cycle *)
        bStartButtonPrev := StartButton;

    1: (* Testing State *)
        (* Update sensor values with limits *)
        NutrientSensorValue := REAL_MIN(NutrientSensorValue + 0.1, 0.9);
        pHSensorValue := REAL_MAX(pHSensorValue - 0.5, 4.0);

        (* Detect rising edge of SoilSampleDetected *)
        IF SoilSampleDetected AND NOT bSampleDetectedPrev THEN
            (* Start verification timer *)
            tSampleVerification(IN:=TRUE, PT:=T#2S);
        END_IF;

        (* Check for completion conditions after verification delay *)
        IF tSampleVerification.Q THEN
            IF (NutrientSensorValue >= NutrientThreshold) AND (pHSensorValue <= pHThreshold) THEN
                (* Conditions met - transition to Completed *)
                TestingStatus := 2;
                NutrientPump := FALSE;
                pHAdjustmentPump := FALSE;
            ELSE
                (* Conditions not met - reset timer for next detection *)
                tSampleVerification(IN:=FALSE);
            END_IF;
        END_IF;

        (* Store current sample detection state for next cycle *)
        bSampleDetectedPrev := SoilSampleDetected;

    2: (* Completed State *)
        (* Ensure pumps remain deactivated *)
        NutrientPump := FALSE;
        pHAdjustmentPump := FALSE;

        (* Reset timer *)
        tSampleVerification(IN:=FALSE, PT:=T#2S);

        (* Reset to Idle when StartButton is released *)
        IF NOT StartButton THEN
            TestingStatus := 0;
        END_IF;

END_CASE;

END_FUNCTION_BLOCK

(*
    FUNCTION_BLOCK: SushiConveyorControl
    Description: Controls an automated sushi conveyor belt with emergency stop, start/stop, and simulated rotation via timed on/off cycles.
    Priority: Emergency Stop (highest) > Start/Stop Control > Simulated Rotation.
    Note: This implementation uses a simple integer counter (ConveyorTimer) for timing. In a real PLC, this would typically be replaced by a hardware timer (TON) or a time-based increment.
*)

FUNCTION_BLOCK SushiConveyorControl
VAR_INPUT
    StartButton : BOOL;     (* Momentary input to start the conveyor *)
    StopButton : BOOL;      (* Momentary input to stop the conveyor *)
    EmergencyStop : BOOL;   (* Hardwired emergency stop signal *)
END_VAR

VAR_OUTPUT
    ConveyorMotor : BOOL;   (* Output signal to the conveyor motor contactor *)
END_VAR

VAR
    BeltRunning : BOOL;     (* Internal state: TRUE when conveyor is running *)
    ConveyorTimer : INT;    (* Counter for simulated rotation timing *)
    RotationTime : INT := 5; (* Duration of one motor ON cycle (e.g., seconds) *)
    CycleActive : BOOL;     (* Internal flag: TRUE during the ON part of the cycle *)
END_VAR

(* Main Logic Execution *)
BEGIN
    (* 1. EMERGENCY STOP - HIGHEST PRIORITY *)
    IF EmergencyStop THEN
        ConveyorMotor := FALSE;
        BeltRunning := FALSE;
        ConveyorTimer := 0;
        CycleActive := FALSE;
        RETURN; (* Immediate exit from the function block *)
    END_IF;

    (* 2. START/STOP CONTROL *)
    IF StartButton AND NOT BeltRunning THEN
        BeltRunning := TRUE;
        ConveyorTimer := 0;
        CycleActive := TRUE;
    ELSIF StopButton AND BeltRunning THEN
        BeltRunning := FALSE;
        ConveyorTimer := 0;
        CycleActive := FALSE;
        ConveyorMotor := FALSE;
    END_IF;

    (* 3. SIMULATED ROTATION (Timed On/Off Cycle) *)
    IF BeltRunning THEN
        (* Increment the timer to simulate passage of time *)
        ConveyorTimer := ConveyorTimer + 1;

        (* Check if the ON cycle duration has been reached *)
        IF ConveyorTimer >= RotationTime THEN
            ConveyorTimer := 0;       (* Reset timer for next cycle *)
            CycleActive := NOT CycleActive; (* Toggle between ON and OFF parts of the cycle *)
        END_IF;

        (* Motor is only energized during the active part of the cycle *)
        ConveyorMotor := CycleActive;
    ELSE
        (* Conveyor is not running, ensure motor is off and timer is reset *)
        ConveyorTimer := 0;
        CycleActive := FALSE;
        ConveyorMotor := FALSE;
    END_IF;

END_FUNCTION_BLOCK

TYPE AGV_Status :
STRUCT
    IsReady : BOOL;
    CurrentTask : INT;
    Position : INT;
    IsWorking : BOOL;
END_STRUCT
END_TYPE

FUNCTION_BLOCK AGVControlSystem
VAR_INPUT
    MaterialRequest : INT; (* New material request, valid if > 0 *)
    ExecuteCycle : BOOL := TRUE; (* Enable processing for the scan cycle *)
END_VAR
VAR_OUTPUT
    AGV1_Ready : BOOL := TRUE;
    AGV2_Ready : BOOL := TRUE;
    AGV3_Ready : BOOL := TRUE;
    QueueCount : INT := 0; (* Number of pending tasks *)
    SystemIdle : BOOL := TRUE; (* All AGVs ready AND queue empty *)
    ErrorCode : INT := 0; (* 0: OK, 1: Queue Overflow, 2: Invalid Request *)
END_VAR
VAR
    MaterialQueue : ARRAY[1..10] OF INT; (* FIFO queue for tasks *)
    QueueHead : INT := 1; (* Index of the next task to dequeue *)
    QueueTail : INT := 1; (* Index where the next task will be enqueued *)
    AGVs : ARRAY[1..3] OF AGV_Status := [(IsReady:=TRUE, CurrentTask:=0, Position:=0, IsWorking:=FALSE),
                                         (IsReady:=TRUE, CurrentTask:=0, Position:=0, IsWorking:=FALSE),
                                         (IsReady:=TRUE, CurrentTask:=0, Position:=0, IsWorking:=FALSE)];
    TaskAssignedThisCycle : BOOL; (* Prevents multiple assignments in one scan *)
    i : INT;
END_VAR

(* 1. Process new material request with validation and overflow protection *)
ErrorCode := 0;
IF ExecuteCycle THEN
    IF MaterialRequest > 0 THEN
        IF QueueCount < 10 THEN
            MaterialQueue[QueueTail] := MaterialRequest;
            QueueTail := QueueTail + 1;
            IF QueueTail > 10 THEN
                QueueTail := 1;
            END_IF;
            QueueCount := QueueCount + 1;
        ELSE
            ErrorCode := 1; (* Queue Overflow *)
        END_IF;
    ELSIF MaterialRequest < 0 THEN
        ErrorCode := 2; (* Invalid Request *)
    END_IF;

    (* 2. Priority-based task assignment (AGV1 > AGV2 > AGV3) *)
    TaskAssignedThisCycle := FALSE;
    FOR i := 1 TO 3 DO
        IF (AGVs[i].IsReady) AND (QueueCount > 0) AND (NOT TaskAssignedThisCycle) THEN
            AGVs[i].CurrentTask := MaterialQueue[QueueHead];
            AGVs[i].IsReady := FALSE;
            AGVs[i].IsWorking := TRUE;
            AGVs[i].Position := 0; (* Reset position at task start *)
            QueueHead := QueueHead + 1;
            IF QueueHead > 10 THEN
                QueueHead := 1;
            END_IF;
            QueueCount := QueueCount - 1;
            TaskAssignedThisCycle := TRUE;
        END_IF;
    END_FOR;

    (* 3. Simulate task execution and handle completion *)
    FOR i := 1 TO 3 DO
        IF AGVs[i].IsWorking THEN
            (* Simulate position update during task execution *)
            AGVs[i].Position := AGVs[i].Position + 1;

            (* Safety constraint: ensure non-negative position *)
            IF AGVs[i].Position < 0 THEN
                AGVs[i].Position := 0;
            END_IF;

            (* Task completion check - example: task completes after 10 position units *)
            IF AGVs[i].Position >= 10 THEN
                (* Release AGV resource *)
                AGVs[i].Position := 0;
                AGVs[i].CurrentTask := 0;
                AGVs[i].IsWorking := FALSE;
                AGVs[i].IsReady := TRUE;
            END_IF;
        END_IF;
    END_FOR;

    (* 4. Update output status *)
    AGV1_Ready := AGVs[1].IsReady;
    AGV2_Ready := AGVs[2].IsReady;
    AGV3_Ready := AGVs[3].IsReady;

    (* 5. State monitoring and synchronization *)
    SystemIdle := (QueueCount = 0) AND AGVs[1].IsReady AND AGVs[2].IsReady AND AGVs[3].IsReady;

    (* 6. Sanity checks for queue indices (defensive programming) *)
    IF QueueHead < 1 OR QueueHead > 10 THEN
        QueueHead := 1;
    END_IF;
    IF QueueTail < 1 OR QueueTail > 10 THEN
        QueueTail := 1;
    END_IF;
    IF QueueCount < 0 THEN
        QueueCount := 0;
    ELSIF QueueCount > 10 THEN
        QueueCount := 10;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

